document.addEventListener('DOMContentLoaded', () => {const prefersReducedMotion = window.matchMedia('(prefers-reduced-motion: reduce)').matches;const initScrollReveal = () => {const targets = document.querySelectorAll('.product-card, .review-card, .blog-card, .newsletter, .trending-strip, .spec-group, .buy-card');if (!targets.length) return;if (prefersReducedMotion) {targets.forEach(el => el.classList.add('revealed'));return;}targets.forEach(el => el.classList.add('reveal-target'));const observer = new IntersectionObserver((entries) => {entries.forEach(entry => {if (entry.isIntersecting) {entry.target.classList.add('revealed');observer.unobserve(entry.target);}});},{ threshold: 0.1, rootMargin: '0px 0px -40px 0px' });targets.forEach(el => observer.observe(el));};const initHeaderEffect = () => {const header = document.querySelector('.site-header');if (!header) return;let lastScroll = 0;let ticking = false;header.style.transition = 'transform 0.3s ease, background 0.3s ease, box-shadow 0.3s ease';const updateHeader = () => {const currentScroll = window.scrollY;if (currentScroll > 50) {header.style.boxShadow = '0 4px 20px rgba(0, 0, 0, 0.08)';} else {header.style.boxShadow = 'none';}if (currentScroll > lastScroll && currentScroll > 300) {header.style.transform = 'translateY(-100%)';} else {header.style.transform = 'translateY(0)';}lastScroll = currentScroll;ticking = false;};window.addEventListener('scroll', () => {if (!ticking) {requestAnimationFrame(updateHeader);ticking = true;}}, { passive: true });};const initSmoothScroll = () => {document.querySelectorAll('a[href^="#"]').forEach(anchor => {anchor.addEventListener('click', function (e) {const targetId = this.getAttribute('href');if (targetId === '#') return;const target = document.querySelector(targetId);if (target) {e.preventDefault();const headerHeight = 100;const targetPosition = target.getBoundingClientRect().top + window.scrollY - headerHeight;window.scrollTo({top: targetPosition,behavior: prefersReducedMotion ? 'auto' : 'smooth'});}});});};const initComparisonSystem = () => {let compareState = [];try { compareState = JSON.parse(localStorage.getItem('affos_compare')) || []; } catch(e) {}const compareUrl = document.body.dataset.compareUrl || '/bandingkan/';let bar = document.querySelector('.compare-bar');if (!bar) {bar = document.createElement('div');bar.className = 'compare-bar';document.body.appendChild(bar);}updateCompareBar();const compareBtns = document.querySelectorAll('.add-to-compare, [data-compare-id]');compareBtns.forEach((btn) => {let pid = btn.dataset.compareId || btn.dataset.id;if (!pid) {const card = btn.closest('[data-product-id]');if (card) {pid = card.dataset.productId;}}if (!pid) return;btn.dataset.compareId = pid;if (compareState.includes(pid)) {btn.classList.add('active');}btn.addEventListener('click', (e) => {e.preventDefault();e.stopPropagation();const id = btn.dataset.compareId;const idx = compareState.indexOf(id);if (idx > -1) {compareState.splice(idx, 1);btn.classList.remove('active');} else {if (compareState.length >= 3) {showToast('Maksimal 3 produk untuk dibandingkan!');return;}compareState.push(id);btn.classList.add('active');}try { localStorage.setItem('affos_compare', JSON.stringify(compareState)); } catch(e) {}updateCompareBar();});});function updateCompareBar() {let state = [];try { state = JSON.parse(localStorage.getItem('affos_compare') || '[]'); } catch(e) {}const isComparePage = window.location.pathname.includes('/bandingkan');if (isComparePage) {bar.classList.remove('active');return;}if (state.length > 0) {let thumbsHtml = state.map(id => `<div class="mini-thumb" data-thumb-id="${id}" data-tooltip="Memuat..."><i class="ri-smartphone-line" aria-hidden="true"></i></div>`).join('');bar.innerHTML = `<div class="container"><div class="compare-items-preview"><span style="font-weight:700;">${state.length} Produk</span>${thumbsHtml}</div><div class="compare-actions"><button class="btn-secondary btn-sm" id="clear-compare">Reset</button><button class="btn-primary btn-sm" id="go-compare">Bandingkan</button></div></div>`;const ajaxUrl = typeof affosData !== 'undefined' ? affosData.ajaxUrl : '/wp-admin/admin-ajax.php';const nonce = typeof affosData !== 'undefined' ? affosData.nonce : '';fetch(ajaxUrl + '?action=affos_get_compare_names&ids=' + state.join(',') + '&_wpnonce=' + nonce).then(r => r.json()).then(data => {if (data.success && data.data) {Object.entries(data.data).forEach(([id, name]) => {const thumb = bar.querySelector(`.mini-thumb[data-thumb-id="${id}"]`);if (thumb) {thumb.setAttribute('data-tooltip', name);thumb.setAttribute('title', name);}});}}).catch(() => { });document.getElementById('clear-compare')?.addEventListener('click', () => {try { localStorage.setItem('affos_compare', '[]'); } catch(e) {}document.querySelectorAll('.add-to-compare, [data-compare-id]').forEach(b => {b.classList.remove('active');});compareState = [];updateCompareBar();});document.getElementById('go-compare')?.addEventListener('click', () => {if (state.length < 2) {showToast('Pilih minimal 2 produk untuk dibandingkan');return;}fetch(ajaxUrl + '?action=affos_get_compare_slugs&ids=' + state.join(',') + '&_wpnonce=' + nonce).then(response => response.json()).then(data => {if (data.success && data.data.url) {window.location.href = data.data.url;} else {window.location.href = compareUrl;}}).catch(() => {window.location.href = compareUrl;});});requestAnimationFrame(() => bar.classList.add('active'));} else {bar.classList.remove('active');}}};const showToast = (message) => {let toast = document.querySelector('.toast-notification');if (!toast) {toast = document.createElement('div');toast.className = 'toast-notification';toast.setAttribute('role', 'alert');toast.setAttribute('aria-live', 'polite');document.body.appendChild(toast);}toast.textContent = message;requestAnimationFrame(() => {toast.classList.add('show');});setTimeout(() => {toast.classList.remove('show');}, 3000);};const initTypingEffect = () => {if (prefersReducedMotion) return;const searchInput = document.querySelector('.hero-search input');if (!searchInput) return;const placeholders = ['Cari iPhone 15 Pro Max...','Cari Samsung Galaxy S24...','Cari MacBook Air M3...','Cari Sony WH-1000XM5...',];let currentIndex = 0;let intervalId;const startTyping = () => {intervalId = setInterval(() => {currentIndex = (currentIndex + 1) % placeholders.length;searchInput.style.transition = 'opacity 0.3s';searchInput.style.opacity = '0.5';setTimeout(() => {searchInput.placeholder = placeholders[currentIndex];searchInput.style.opacity = '1';}, 150);}, 4000);};document.addEventListener('visibilitychange', () => {if (document.hidden) {clearInterval(intervalId);} else {startTyping();}});startTyping();};const initTableOfContents = () => {const tocContainer = document.querySelector('#toc-nav, .toc-list');const articleContent = document.querySelector('.article-content');if (!tocContainer || !articleContent) return;const headings = articleContent.querySelectorAll('h2, h3, h4');if (headings.length === 0) {const tocCard = tocContainer.closest('.sidebar-card');if (tocCard) tocCard.style.display = 'none';return;}tocContainer.innerHTML = '';headings.forEach((heading, index) => {if (!heading.id) {heading.id = `heading-${index + 1}`;}const tocItem = document.createElement('a');tocItem.href = `#${heading.id}`;tocItem.className = 'toc-item';tocItem.textContent = heading.textContent;if (heading.tagName === 'H3') {tocItem.classList.add('toc-h3');tocItem.style.paddingLeft = '1rem';} else if (heading.tagName === 'H4') {tocItem.classList.add('toc-h4');tocItem.style.paddingLeft = '1.5rem';}tocContainer.appendChild(tocItem);});const observerOptions = {rootMargin: '-100px 0px -70% 0px',threshold: 0};const tocObserver = new IntersectionObserver((entries) => {entries.forEach(entry => {const id = entry.target.id;const tocLink = tocContainer.querySelector(`a[href="#${id}"]`);if (entry.isIntersecting) {tocContainer.querySelectorAll('.toc-item').forEach(item => {item.classList.remove('active');});if (tocLink) {tocLink.classList.add('active');}}});}, observerOptions);headings.forEach(heading => {tocObserver.observe(heading);});};const initArchiveFilters = () => {document.querySelectorAll('.filter-bar').forEach(bar => {const filterBtns = bar.querySelectorAll('.filter-btn[data-filter]');const searchInput = bar.querySelector('.filter-search input');if (!filterBtns.length) return;const grid = document.querySelector('.product-grid, .review-grid, .blog-grid');if (!grid) return;const getCards = () => grid.querySelectorAll('[data-category]');const applyFilters = () => {const activeFilter = bar.querySelector('.filter-btn.active')?.dataset.filter || 'all';const searchTerm = searchInput?.value.toLowerCase() || '';getCards().forEach(card => {const matchCategory = activeFilter === 'all' || card.dataset.category === activeFilter;const matchSearch = !searchTerm || card.textContent.toLowerCase().includes(searchTerm);card.style.display = matchCategory && matchSearch ? '' : 'none';});};filterBtns.forEach(btn => {btn.addEventListener('click', () => {filterBtns.forEach(b => b.classList.remove('active'));btn.classList.add('active');applyFilters();});});if (searchInput) {let filterTimeout;searchInput.addEventListener('input', function() {clearTimeout(filterTimeout);filterTimeout = setTimeout(function() {applyFilters();}, 250);});}});};const trapFocus = (element) => {const focusableSelectors = 'a[href], button:not([disabled]), textarea, input, select, [tabindex]:not([tabindex="-1"])';const focusableElements = element.querySelectorAll(focusableSelectors);const firstFocusable = focusableElements[0];const lastFocusable = focusableElements[focusableElements.length - 1];const handleTab = (e) => {if (e.key !== 'Tab') return;if (e.shiftKey) {if (document.activeElement === firstFocusable) {lastFocusable.focus();e.preventDefault();}} else {if (document.activeElement === lastFocusable) {firstFocusable.focus();e.preventDefault();}}};element.addEventListener('keydown', handleTab);return () => element.removeEventListener('keydown', handleTab);};const initMobileMenu = () => {const menuToggle = document.getElementById('mobile-menu-toggle');const overlay = document.getElementById('mobile-menu');const closeBtn = document.getElementById('close-mobile-menu');const mobileLinks = document.querySelectorAll('.mobile-nav-links a');if (!menuToggle || !overlay) return;let removeTrap = null;const openMenu = () => {overlay.classList.add('open');document.body.style.overflow = 'hidden';menuToggle.setAttribute('aria-expanded', 'true');removeTrap = trapFocus(overlay);if (closeBtn) closeBtn.focus();};const closeMenu = () => {overlay.classList.remove('open');document.body.style.overflow = '';menuToggle.setAttribute('aria-expanded', 'false');if (removeTrap) {removeTrap();removeTrap = null;}menuToggle.focus();};menuToggle.addEventListener('click', openMenu);if (closeBtn) {closeBtn.addEventListener('click', closeMenu);}mobileLinks.forEach(link => {link.addEventListener('click', closeMenu);});overlay.addEventListener('click', (e) => {if (e.target === overlay) {closeMenu();}});overlay.addEventListener('keydown', (e) => {if (e.key === 'Escape') {closeMenu();}});};const initSearchToggle = () => {const searchToggle = document.getElementById('search-toggle');const searchOverlay = document.getElementById('search-overlay');const searchClose = document.getElementById('search-close');const searchInput = document.querySelector('.search-overlay .search-input');if (!searchToggle) return;let removeTrap = null;const openSearch = () => {if (searchOverlay) {searchOverlay.classList.add('active');document.body.style.overflow = 'hidden';removeTrap = trapFocus(searchOverlay);if (searchInput) searchInput.focus();}};const closeSearch = () => {if (searchOverlay) {searchOverlay.classList.remove('active');document.body.style.overflow = '';if (removeTrap) {removeTrap();removeTrap = null;}searchToggle.focus();}};searchToggle.addEventListener('click', openSearch);if (searchClose) {searchClose.addEventListener('click', closeSearch);}document.addEventListener('keydown', (e) => {if (e.key === 'Escape' && searchOverlay?.classList.contains('active')) {closeSearch();}});};const initShowDiffOnly = () => {const checkbox = document.getElementById('show-diff-only');if (!checkbox) return;checkbox.addEventListener('change', () => {const rows = document.querySelectorAll('.compare-spec-row');rows.forEach(row => {if (!checkbox.checked) {row.style.display = '';return;}const values = Array.from(row.querySelectorAll('.spec-value:not(.empty)')).map(cell => cell.textContent.trim());const allSame = values.length > 1 && values.every(v => v === values[0]);row.style.display = allSame ? 'none' : '';});});};initScrollReveal();initHeaderEffect();initSmoothScroll();initComparisonSystem();initTypingEffect();initTableOfContents();initArchiveFilters();initMobileMenu();initSearchToggle();initShowDiffOnly();document.querySelectorAll('[data-share-url]').forEach(function(btn) {btn.addEventListener('click', function() {window.open(this.dataset.shareUrl, '_blank');});});document.querySelectorAll('[data-copy-url]').forEach(function(btn) {btn.addEventListener('click', function() {navigator.clipboard.writeText(this.dataset.copyUrl).then(function() { alert('Link copied!'); }).catch(function() {});});});document.querySelectorAll('[data-newsletter]').forEach(function(form) {form.addEventListener('submit', function(e) {e.preventDefault();var emailInput = form.querySelector('input[type="email"]');var btn = form.querySelector('button[type="submit"]');if (!emailInput || !emailInput.value) return;var originalText = btn.textContent;btn.disabled = true;btn.textContent = '...';var data = new FormData();data.append('action', 'affos_newsletter_subscribe');data.append('nonce', (typeof affosData !== 'undefined') ? affosData.nonce : '');data.append('email', emailInput.value);fetch((typeof affosData !== 'undefined') ? affosData.ajaxUrl : '/wp-admin/admin-ajax.php', {method: 'POST',body: data,}).then(function(r) { return r.json(); }).then(function(res) {var msg = (res.data && typeof res.data === 'string') ? res.data : (res.success ? 'Berhasil!' : 'Gagal.');btn.textContent = msg;if (res.success) {emailInput.value = '';}setTimeout(function() {btn.textContent = originalText;btn.disabled = false;}, 3000);}).catch(function() {btn.textContent = 'Error';setTimeout(function() {btn.textContent = originalText;btn.disabled = false;}, 3000);});});});});